const hora = new Date().getHours();
let periodo = 'TARDE';
if (hora >= 5 && hora < 12) periodo = 'MANHA';
if (hora >= 18) periodo = 'NOITE';

const saudacoes = {
  MANHA: 'Bom dia, Diretor.',
  TARDE: 'Boa tarde, Diretor.',
  NOITE: 'Boa noite, Diretor.'
};

return [{
  json: {
    periodo: periodo,
    saudacao: saudacoes[periodo],
    hora: hora,
    data: new Date().toLocaleDateString('pt-BR'),
    timestamp: new Date().toISOString()
  }
}];

